import json
from dataclasses import dataclass, fields


@dataclass(frozen=True)
class Config:
    title: str = "Report"
    output_format: str = "text"  # "text" or "markdown"
    max_rows: int = 10
    include_summary: bool = True


def load_config(path) -> Config:
    """Load config from a JSON file, filling in defaults for missing keys."""
    with open(path) as f:
        raw = json.load(f)

    known_settings = {field.name for field in fields(Config)}
    for key in raw:
        if key not in known_settings:
            raise ValueError(f"Unknown config setting: {key}")

    return Config(**raw)

